	@Test
	void reorderJoinArgsAllowsZeroCostCandidates() throws Exception {
		StatementPattern a = statementPattern("a", "ex:pA");
		StatementPattern b = statementPattern("b", "ex:pB");
		StatementPattern c = statementPattern("c", "ex:pC");

		Deque<TupleExpr> ordered = new ArrayDeque<>(List.of(a, b, c));
		Map<String, Double> joinCosts = new HashMap<>();
		joinCosts.put(pairKey("ex:pA", "ex:pB"), 0.0d);
		joinCosts.put(pairKey("ex:pA", "ex:pC"), 2.0d);
		joinCosts.put(pairKey("ex:pB", "ex:pC"), 5.0d);

		QueryJoinOptimizer optimizer = new QueryJoinOptimizer(new PairwiseCostStatistics(joinCosts),
				new EmptyTripleSource());
		Deque<TupleExpr> reordered = invokeReorderJoinArgs(optimizer, ordered);

		List<String> predicates = reordered.stream()
				.map(QueryJoinOptimizerReorderSafetyTest::predicate)
				.collect(Collectors.toList());

		assertThat(predicates).containsExactly("ex:pA", "ex:pB", "ex:pC");
	}

